module top_module(clk, Reset, PCWre, nextAddress, obf_Address);input clk, Reset, PCWre;
    input [31:0] nextAddress;
    output reg [31:0] obf_Address;
    always @(posedge clk)begin
        if (Reset == 0)
            obf_Address = 0;
        else if(PCWre==1)
            obf_Address = nextAddress;
    end
endmodule
